function decodeXml(value) {
  return value
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'");
}

function stripCdata(value) {
  return value.replace(/^<!\[CDATA\[/, '').replace(/\]\]>$/, '');
}

function getTag(entry, tagName) {
  const match = entry.match(new RegExp(`<${tagName}[^>]*>([\\s\\S]*?)</${tagName}>`));
  return match ? decodeXml(stripCdata(match[1].trim())) : '';
}

function getAlternateLink(entry) {
  const match = entry.match(/<link\b[^>]*rel=["']alternate["'][^>]*href=["']([^"']+)["'][^>]*\/?>/);
  return match ? decodeXml(match[1]) : '';
}

const feed = $input.first().json.data;
const entries = [...feed.matchAll(/<entry>([\s\S]*?)<\/entry>/g)]
  .map((match) => match[1])
  .map((entry) => {
    const title = getTag(entry, 'title');
    const videoId = getTag(entry, 'yt:videoId');
    const link = videoId ? `https://www.youtube.com/watch?v=${videoId}` : getAlternateLink(entry);
    return { title, link };
  })
  .filter((entry) => entry.title && entry.link);

if (entries.length === 0) {
  throw new Error('No YouTube videos found in feed');
}

const selected = entries[Math.floor(Math.random() * entries.length)];

return [
  {
    json: {
      title: selected.title,
      link: selected.link,
      text: selected.title,
    },
  },
];
